uired": true, "placeholder": ""}]','2025-11-13 17:10:16.078+00','2026-02-09 18:11:56.896898+00','lead','{"cardColor": "#ffffff", "textColor": "#1e293b", "fontFamily": "Inter", "borderRadius": "12", "primaryColor": "#1eff00", "backgroundColor": "#ffffff"}','9c8c0033-15ea-4e33-a55f-28d81a19693b',NULL);
INSERT INTO "form_templates" ("id","name","description","slug","fields","created_at","updated_at","form_type","style","organization_id","lead_qualification") VALUES ('86287635-c77f-405d-9260-19336f6c1cbd','Seleção Exclusiva para o Onboarding Premium 1:1','','onboarding','[{"id": "field_1764174411900", "name": "field_4", "type": "phone", "label": "Qual o seu whatsapp?", "required": true, "mapToLead": "none", "placeholder": ""}, {"id": "field_1764173327467", "name": "field_1", "type": "checkbox", "label": "1. Qual é o seu maior problema hoje:", "options": ["Capacitação técnica", "Posicionamento digital", "Gestão", "Marketing", "Vendas"], "required": true, "mapToLead": "none", "placeholder": ""}, {"id": "field_1764173531513", "name": "field_2", "type": "text", "label": "Qual é o seu instagram?", "required": true, "mapToLead": "none", "placeholder": ""}, {"id": "field_1764174249237", "name": "field_3", "type": "checkbox", "label": "Situação atual:", "options": ["Dependo do SUS", "Não dependo do SUS"], "required": true, "mapToLead": "none", "placeholder": ""}]','2025-11-26 16:25:41.068+00','2026-02-09 18:11:56.896898+00','other','{"cardColor": "#ffffff", "textColor": "#1e293b", "fontFamily": "Inter", "borderRadius": "12", "primaryColor": "#3b82f6", "backgroundColor": "#f8fafc"}','9c8c0033-15ea-4e33-a55f-28d81a19693b',NULL);
INSERT INTO "form_templates" ("id","name","description","slug","fields","created_at","updated_at","form_type","style","organization_id","lead_qualification") VALUES ('ca8b5c62-cb53-4f77-8929-50cb13b60efc','NPS Mentoria Médicos de Resultado','Pesquisa completa de satisfação da mentoria médica','nps-mentoria','[{"id": "field_2", "name": "nota_nps", "type": "number", "label": "De 0 a 10, o quanto você recomendaria a Mentoria Médicos de Resultado para outro médico que quer sair do SUS/plantão e construir uma clínica ou negócio médico lucrativo?", "required": true, "placeholder": "Digite uma nota de 0 a 10"}, {"id": "field_3", "name": "valor_percebido", "type": "radio", "label": "Hoje, olhando para o que você já aplicou, como você avalia o valor da mentoria em relação ao investimento financeiro feito?", "options": ["Muito abaixo do esperado", "Abaixo do esperado", "Dentro do esperado", "Acima do esperado", "Muito acima do esperado"], "required": true}, {"id": "field_4", "name": "principal_transformacao", "type": "radio", "label": "Qual foi a principal transformação que você teve até agora após entrar na mentoria?", "options": ["Clareza de direção e estratégia", "Mudança de mentalidade como médico-empresário", "Organização e estrutura do negócio", "Aumento de faturamento", "Saída parcial ou total do SUS/plantão", "Ainda não tive uma transformação clara"], "required": true}, {"id": "field_5", "name": "nivel_aplicacao", "type": "radio", "label": "O quanto você consegue aplicar, na prática, o que é ensinado na mentoria?", "options": ["Aplico tudo de forma consistente", "Aplico boa parte", "Aplico pouco", "Tenho dificuldade de aplicar", "Ainda não comecei a aplicar"], "required": true}, {"id": "field_6", "name": "qualidade_suporte", "type": "radio", "label": "Como você avalia o suporte da mentoria (comunidade, time, acompanhamento, respostas)?", "options": ["Excelente", "Muito bom", "Bom", "Regular", "Ruim"], "required": true}, {"id": "field_7", "name": "influencia_mentor", "type": "radio", "label": "O quanto a minha presença, direcionamento e visão estratégica influenciam suas decisões como médico e empreendedor hoje?", "options": ["Influenciam totalmente", "Influenciam bastante", "Influenciam moderadamente", "Influenciam pouco", "Não influenciam"], "required": true}, {"id": "field_8", "name": "expectativa_futura", "type": "radio", "label": "Você acredita que, mantendo a aplicação do método, seu resultado nos próximos 6–12 meses será significativamente maior do que hoje?", "options": ["Sim, com muita clareza", "Sim", "Talvez", "Não tenho certeza", "Não"], "required": true}, {"id": "field_9", "name": "objecoes_ocultas", "type": "textarea", "label": "O que hoje mais te impede de avançar mais rápido dentro da mentoria?", "required": false, "placeholder": "Falta de tempo, execução, ambiente familiar, priorização..."}, {"id": "field_10", "name": "prova_social", "type": "textarea", "label": "Se você tivesse que explicar para outro médico por que essa mentoria é diferente das outras, o que você diria?", "required": false, "placeholder": "Sua resposta pode virar copy de lançamento..."}]','2025-12-17 17:34:22.612+00','2026-02-09 18:11:56.896898+00','nps','{"cardColor": "#ffffff", "textColor": "#1e293b", "fontFamily": "Inter", "borderRadius": "12", "primaryColor": "#10b981", "backgroundColor": "#f0fdf4"}','9c8c0033-15ea-4e33-a55f-28d81a19693b',NULL);
INSERT INTO "form_templates" ("id","name","description","slug","fields","created_at","updated_at","form_type","style","organization_id","lead_qualification") VALUES ('c44688e3-6c3b-4493-89ba-28e7b4e1362e','Qualificação Médica','Formulário avançado de qualificação para médicos. Avalie seu perfil profissional e receba orientações personalizadas.','qualificacao-medica','[{"id": "1", "name": "nome_completo", "type": "text", "label": "Qual o seu nome completo?", "required": true, "mapToLead": "nome_completo", "placeholder": "Dr(a). Seu nome completo"}, {"id": "2", "name": "email", "type": "email", "label": "Qual o seu email?", "required": true, "mapToLead": "email", "placeholder": "seu.email@exemplo.com"}, {"id": "3", "name": "whatsapp", "type": "text", "label": "Qual o seu WhatsApp?", "required": true, "mapToLead": "telefone", "placeholder": "(00) 00000-0000"}, {"id": "4", "name": "principal_fonte_renda", "type": "radio", "label": "Qual sua principal fonte de renda?", "options": ["Plantão", "SUS", "Convênios", "Consultório próprio", "Misto (várias fontes)"], "required": true}, {"id": "5", "name": "tempo_formado", "type": "radio", "label": "Há quanto tempo você é formado?", "options": ["Menos de 2 anos", "Entre 2 e 5 anos", "Entre 5 e 10 anos", "Mais de 10 anos"], "required": true}, {"id": "6", "name": "renda_mensal", "type": "radio", "label": "Qual sua renda mensal aproximada?", "options": ["Até R$ 15.000", "R$ 15.000 - R$ 30.000", "R$ 30.000 - R$ 60.000", "Acima de R$ 60.000"], "required": true}, {"id": "7", "name": "plantoes_por_semana", "type": "radio", "label": "Quantos plantões você faz por semana?", "options": ["Nenhum", "1 a 2 plantões", "3 a 4 plantões", "5 ou mais plantões"], "required": true}, {"id": "8", "name": "dependencia_horas", "type": "radio", "label": "Sua renda depende das horas trabalhadas?", "options": ["Quase tudo depende das horas", "Mais da metade depende", "Menos da metade depende", "Pouco ou nada depende"], "required": true}, {"id": "9", "name": "o_que_mais_incomoda", "type": "textarea", "label": "O que mais te incomoda na sua carreira médica hoje?", "required": true, "placeholder": "Descreva suas principais frustações, desafios ou insatisfações..."}, {"id": "10", "name": "visao_3_anos", "type": "textarea", "label": "Como você se vê daqui a 3 anos?", "required": true, "placeholder": "Descreva sua visão ideal para o futuro da sua carreira..."}, {"id": "11", "name": "ja_tentou_consultorio", "type": "radio", "label": "Já tentou abrir consultório antes?", "options": ["Não, nunca tentei", "Sim, tentei sozinho", "Sim, com curso/mentoria", "Já tenho algo funcionando"], "required": true}, {"id": "12", "name": "objetivo_principal", "type": "radio", "label": "Qual seu objetivo principal?", "options": ["Ganhar mais dinheiro", "Trabalhar menos horas", "Ter liberdade e autonomia", "Estou confuso sobre meus objetivos"], "required": true}, {"id": "13", "name": "condicoes_investir", "type": "radio", "label": "Tem condições de investir em mentoria/consultoria?", "options": ["Sim, tenho recursos disponíveis", "Sim, mas com planejamento", "Não tenho condições no momento"], "required": true}, {"id": "14", "name": "estilo_decisao", "type": "radio", "label": "Como você toma decisões?", "options": ["Decido rapidamente quando vejo valor", "Analiso bem antes de decidir", "Costumo travar nas decisões"], "required": true}, {"id": "15", "name": "por_que_agora", "type": "textarea", "label": "Por que agora é o momento certo para mudar sua situação?", "required": true, "placeholder": "O que te motivou a buscar uma solução agora? O que mudou?"}]','2026-02-09 15:16:39.891271+00','2026-02-09 18:12:20.432182+00','lead','{"cardColor": "#ffffff", "textColor": "#1e293b", "fontFamily": "Inter", "borderRadius": "12", "primaryColor": "#059669", "backgroundColor": "#ffffff"}','9c8c0033-15ea-4e33-a55f-28d81a19693b',NULL);
INSERT INTO "form_templates" ("id","name","description","slug","fields","created_at","updated_at","form_type","style","organization_id","lead_qualification") VALUES ('6b866d0e-ac82-4cf2-8f01-2fb2cc0f4993','Qualificação Medico de Resultado','O Médicos de Resultado foi criado para médicos que desejam se livrar dos plantões e deixar de depender do estado para ter uma vida livre, com qualidade, e romper os 100 mil de faturamento mensal trabalhando 20 horas semanais Ao longo de 12 meses, guiamos você em quatro frentes essenciais:\n\nCapacitação técnica, posicionamento digital, gestão e vendas.','liberdade','[{"id": "field_1763140113645", "name": "nome_completo", "type": "text", "label": "Qual o seu nome?", "required": true, "mapToLead": "nome_completo", "placeholder": "Gabriel Maia"}, {"id": "field_1763052159850", "name": "telefone", "type": "phone", "label": "Qual o seu telefone?", "required": true, "mapToLead": "telefone", "placeholder": "(11)11111-1111"}, {"id": "field_1763052643847", "name": "instagram ", "type": "text", "label": "Qual o seu instagram profissional?", "required": true, "placeholder": "@instagram"}, {"id": "field_1763052669112", "name": "email", "type": "email", "label": "Qual o seu e-mail?", "required": true, "mapToLead": "email", "placeholder": "seuemail@email.com"}, {"id": "field_1763052700796", "name": "situacaoAtual", "type": "checkbox", "label": "Situação atual:", "options": ["trabalho apenas fazendo plantão.", "Trabalho com plantão + UBS.", "Trabalho com particular + SUS/Convênio.", "Trabalho apenas com particular."], "required": true, "placeholder": ""}, {"id": "field_1763052737680", "name": "problema", "type": "checkbox", "label": "Qual o seu maior problema hoje?", "options": ["capacitação técnica.", "posicionamento digital.", "gestão.", "marketing.", "vendas."], "required": true, "placeholder": ""}, {"id": "field_1763052775224", "name": "investimento", "type": "checkbox", "label": "O investimento para participar dos nossos programas é entre R$ 5.996 e R$ 116.400. Você gostaria de seguir com o processo seletivo?", "options": ["Quero avaliar opções de parcelamento.", "Ainda não estou decidido, quero mais informações.", "Pagamento à vista."], "required": true, "placeholder": ""}]','2025-11-13 16:54:04.096+00','2026-02-09 18:11:56.896898+00','lead','{"cardColor": "#ffffff", "textColor": "#1e293b", "fontFamily": "Inter", "borderRadius": "12", "primaryColor": "#3b82f6", "backgroundColor": "#f8fafc"}','9c8c0033-15ea-4e33-a55f-28d81a19693b',NULL);
