INSERT INTO "form_templates" ("id","name","description","slug","fields","created_at","updated_at","form_type","style","organization_id","lead_qualification") VALUES ('aaf9af61-2f16-4e3d-af5a-cd7eb1a7d0c3','Pesquisa ICP - Mentorados','Formulário para entender melhor o perfil dos mentorados e criar conteúdos mais direcionados','icp-mentorados-2024','[{"id": "idade", "type": "number", "label": "Qual a sua idade?", "required": true, "placeholder": "Ex: 28"}, {"id": "genero", "type": "select", "label": "Gênero", "options": ["Masculino", "Feminino", "Não binário", "Prefiro não informar"], "required": true}, {"id": "estado", "type": "select", "label": "Estado", "options": ["Acre - AC", "Alagoas - AL", "Amapá - AP", "Amazonas - AM", "Bahia - BA", "Ceará - CE", "Distrito Federal - DF", "Espírito Santo - ES", "Goiás - GO", "Maranhão - MA", "Mato Grosso - MT", "Mato Grosso do Sul - MS", "Minas Gerais - MG", "Pará - PA", "Paraíba - PB", "Paraná - PR", "Pernambuco - PE", "Piauí - PI", "Rio de Janeiro - RJ", "Rio Grande do Norte - RN", "Rio Grande do Sul - RS", "Rondônia - RO", "Roraima - RR", "Santa Catarina - SC", "São Paulo - SP", "Sergipe - SE", "Tocantins - TO"], "required": true}, {"id": "cidade", "type": "text", "label": "Cidade", "required": true, "placeholder": "Ex: São Paulo"}, {"id": "universidade", "type": "text", "label": "Em qual universidade você se formou?", "required": true, "placeholder": "Ex: Universidade Federal de São Paulo (UNIFESP)"}, {"id": "tipo_universidade", "type": "select", "label": "Sua universidade era:", "options": ["Pública Federal", "Pública Estadual", "Pública Municipal", "Privada"], "required": true}, {"id": "anos_formado", "type": "number", "label": "Quantos anos você tem de formado?", "required": true, "placeholder": "Ex: 5"}, {"id": "conheceu_mentoria", "type": "select", "label": "Por onde você conheceu a mentoria?", "options": ["Instagram", "YouTube", "Indicação de amigo/colega", "Google/Pesquisa", "LinkedIn", "Facebook", "TikTok", "Evento/Palestra", "Outro"], "required": true}, {"id": "tempo_acompanha", "type": "select", "label": "Há quanto tempo você acompanha o perfil?", "options": ["Menos de 1 mês", "1-3 meses", "3-6 meses", "6 meses - 1 ano", "1-2 anos", "Mais de 2 anos"], "required": true}, {"id": "viu_anuncios", "type": "select", "label": "Você se lembra de ter visto anúncios patrocinados meus no Instagram dentro dos últimos três meses?", "options": ["Sim, vejo frequentemente", "Sim, vi algumas vezes", "Lembro de ter visto pelo menos uma vez", "Não me lembro", "Não, nunca vi"], "required": true}, {"id": "desejos_mentoria", "type": "textarea", "label": "Quais são os seus principais desejos com a mentoria? (seja bem específico - isso nos ajuda a criar conteúdos mais direcionados)", "required": true, "placeholder": "Ex: Quero aprender a precificar meus procedimentos corretamente, entender como fazer marketing médico sem ferir o CFM, aumentar meu faturamento em 50% nos próximos 6 meses..."}, {"id": "sucesso_mentoria", "type": "textarea", "label": "O que precisa acontecer para que você considere que a mentoria valeu a pena? (seja específico com metas e resultados)", "required": true, "placeholder": "Ex: Dobrar meu faturamento mensal, conseguir 100 pacientes novos por mês, ter uma agenda cheia por 3 meses seguidos, abrir uma nova unidade..."}]','2026-02-24 06:02:24.529902+00','2026-02-24 06:08:15.925754+00','survey',NULL,'d0bc922d-de87-42d9-a4de-9b2095191719',NULL);
